def solve(nums: list[int], k: int) -> int:
    prefix_sum = 0
    mod_map = {0: -1}
    segments = []
    n = len(nums)

    # First pass to find all removable segments
    for i in range(n):
        prefix_sum += nums[i]
        mod = prefix_sum % k
        if mod in mod_map:
            segments.append((mod_map[mod] + 1, i))
        mod_map[mod] = i

    # Merge overlapping or adjacent segments
    if not segments:
        return sum(nums)

    segments.sort()
    merged = [segments[0]]
    for seg in segments[1:]:
        last = merged[-1]
        if seg[0] <= last[1]:
            # Overlapping or adjacent, merge them
            new_seg = (last[0], max(last[1], seg[1]))
            merged[-1] = new_seg
        else:
            merged.append(seg)

    # Collect all indices to be removed
    remove_indices = set()
    for seg in merged:
        for i in range(seg[0], seg[1] + 1):
            remove_indices.add(i)

    # Calculate the remaining sum
    remaining_sum = 0
    for i in range(n):
        if i not in remove_indices:
            remaining_sum += nums[i]

    return remaining_sum
